20	using namespace ngp;
21	
22	__launch_bounds__(128, 4) __global__ void render_nerf(
23		uint32_t sample_index,
24		ivec2 resolution,
25		vec2 focal_length,
26		mat4x3 camera_matrix0,
27		mat4x3 camera_matrix1,
28		vec4 rolling_shutter,
29		vec2 screen_center,
30		vec3 parallax_shift,
31		bool snap_to_pixel_centers,
32		BoundingBox render_aabb,
33		mat3 render_aabb_to_local,
34		float near_distance,
35		float plane_z,
36		float aperture_size,
37		Foveation foveation,
38		Lens lens,
39		BoundingBox train_aabb,
40		const uint8_t* __restrict__ density_grid,
41		uint32_t min_mip,
42		uint32_t max_mip,
43		float cone_angle_constant,
44		Buffer2DView<const vec4> envmap,
45		vec4* __restrict__ frame_buffer,
46		float* __restrict__ depth_buffer,
47		Buffer2DView<const uint8_t> hidden_area_mask,
48		Buffer2DView<const vec2> distortion,
49		ERenderMode render_mode,
50		const network_precision_t* __restrict__ params,
51		const float* __restrict__ extra_dims,
52		ENerfActivation density_activation,
53		ENerfActivation rgb_activation,
54		float min_transmittance,
55		bool train_in_linear_colors,
56		bool surface_rendering,
57		float surface_rendering_threshold
58	) {
59		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
60		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
61	
62		bool valid = x < resolution.x && y < resolution.y;
63		uint32_t idx = x + resolution.x * y;
64	
65		vec2 pixel_offset = ld_random_pixel_offset(snap_to_pixel_centers ? 0 : sample_index);
66		vec2 uv = vec2{(float)x + pixel_offset.x, (float)y + pixel_offset.y} / vec2(resolution);
67		mat4x3 camera =
68			get_xform_given_rolling_shutter({camera_matrix0, camera_matrix1}, rolling_shutter, uv, ld_random_val(sample_index, idx * 72239731));
69	
70		Ray ray = uv_to_ray(
71			sample_index,
72			uv,
73			resolution,
74			focal_length,
75			camera,
76			screen_center,
77			parallax_shift,
78			near_distance,
79			plane_z,
80			aperture_size,
81			foveation,
82			hidden_area_mask,
83			lens,
84			distortion
85		);
86	
87		bool alive = valid && ray.is_valid();
88	
89		ray.d = normalize(ray.d);
90		float t = fmaxf(render_aabb.ray_intersect(render_aabb_to_local * ray.o, render_aabb_to_local * ray.d).x, 0.0f) + 1e-6f;
91	
92		alive &= render_aabb.contains(render_aabb_to_local * ray(t));
93	
94		vec3 idir = vec3(1.0f) / ray.d;
95		vec4 color = vec4(0.0f);
96	
97		vec3 cam_fwd = camera[2];
98		vec3 cam_pos = camera[3];
99		float best_depth_candidate = MAX_DEPTH();
100	
101		float cone_angle = calc_cone_angle(dot(ray.d, cam_fwd), focal_length, cone_angle_constant);
102		t = advance_n_steps(t, cone_angle, ld_random_val(sample_index, idx * 786433));
103	
104		float max_weight = 0.0f;
105	
106		while (true) {
107			// Advance to next occupied voxel
108			vec3 pos = cam_pos;
109	
110			if (alive) {
111				t = if_unoccupied_advance_to_next_occupied_voxel(
112					t, cone_angle, ray, idir, density_grid, min_mip, max_mip, render_aabb, render_aabb_to_local
113				);
114				alive &= t < MAX_DEPTH();
115				if (alive) {
116					pos = ray(t);
117				}
118			}
119	
120			// Evaluate NeRF model
121			float dt = calc_dt(t, cone_angle);
122			constexpr uint32_t N_NERF_COORDS = sizeof(NerfCoordinate) / sizeof(float);
123			vec<N_NERF_COORDS + N_EXTRA_DIMS> nerf_in;
124			*(NerfCoordinate*)&nerf_in[0] = {warp_position(pos, train_aabb), warp_direction(ray.d), warp_dt(dt)};
125	
126			NGP_PRAGMA_UNROLL
127			for (uint32_t i = 0; i < N_EXTRA_DIMS; ++i) {
128				nerf_in[N_NERF_COORDS + i] = extra_dims[i];
129			}
130	
131			// Implicit sync is fine here, because the following nerf model wants synchronized warps anyway
132			if (__all_sync(0xFFFFFFFF, !alive)) {
133				break;
134			}
135	
136			vec4 nerf_out = eval_nerf(nerf_in, params);
137	
138			// All threads in the warp must execute the above MLPs for coherence reasons.
139			// Starting from here, it's fine to skip computation.
140			if (!alive) {
141				continue;
142			}
143	
144			t += dt;
145	
146			// Composit color
147			float alpha = 1.f - __expf(-network_to_density(nerf_out.w, density_activation) * dt);
148			float weight = alpha * (1.0f - color.a);
149			vec3 rgb = network_to_rgb_vec(nerf_out.xyz(), rgb_activation);
150			color += vec4(rgb * weight, weight);
151	
152			if (weight > max_weight) {
153				max_weight = weight;
154				best_depth_candidate = lens.is_360() ? distance(pos, cam_pos) : dot(cam_fwd, pos - cam_pos);
155			}
156	
157			if (surface_rendering && alpha >= surface_rendering_threshold) {
158				// Surface rendering: return the first surface point that has a sufficient occupancy
159				color.rgb() = rgb;
160				color.a = 1.0f;
161				best_depth_candidate = lens.is_360() ? distance(pos, cam_pos) : dot(cam_fwd, pos - cam_pos);
162				alive = false;
163			} else if (color.a > (1.0f - min_transmittance)) {
164				color /= color.a;
165				alive = false;
166			}
167		}
168	
169		if (!valid) {
170			return;
171		}
172	
173		if (!train_in_linear_colors) {
174			color.rgb() = srgb_to_linear(color.rgb());
175		}
176	
177		depth_buffer[idx] = color.a > 0.2f ? best_depth_candidate : MAX_DEPTH();
178	
179		if (envmap) {
180			color += read_envmap(envmap, ray.d) * (1.0f - color.a);
181		}
182	
183		frame_buffer[idx] = color;
184	}
