612	
613		vec4 local_rgba = rgba[i];
614		float local_depth = depth[i];
615		vec3 origin = payload.origin;
616		vec3 cam_fwd = camera_matrix[2];
617		// Composite in the last n steps
618		uint32_t actual_n_steps = payload.n_steps;
619		uint32_t j = 0;
620	
621		for (; j < actual_n_steps; ++j) {
622			tvec<network_precision_t, 4> local_network_output;
623			local_network_output[0] = network_output[i + j * n_elements + 0 * stride];
624			local_network_output[1] = network_output[i + j * n_elements + 1 * stride];
625			local_network_output[2] = network_output[i + j * n_elements + 2 * stride];
626			local_network_output[3] = network_output[i + j * n_elements + 3 * stride];
627			const NerfCoordinate* input = network_input(i + j * n_elements);
628			vec3 warped_pos = input->pos.p;
629			vec3 pos = unwarp_position(warped_pos, aabb);
630	
631			float T = 1.f - local_rgba.a;
632			float dt = unwarp_dt(input->dt);
633			float alpha = 1.f - __expf(-network_to_density(float(local_network_output[3]), density_activation) * dt);
634			if (show_accel >= 0) {
635				alpha = 1.f;
636			}
637			float weight = alpha * T;
638	
639			vec3 rgb = network_to_rgb_vec(local_network_output, rgb_activation);
640	
641			if (render_mode == ERenderMode::Normals) {
642				// Network input contains the gradient of the network output w.r.t. input.
643				// So to compute density gradients, we need to apply the chain rule.
644				// The normal is then in the opposite direction of the density gradient (i.e. the direction of decreasing density)
645				vec3 normal = -network_to_density_derivative(float(local_network_output[3]), density_activation) * warped_pos;
646				rgb = normalize(normal);
647			} else if (render_mode == ERenderMode::Positions) {
648				rgb = (pos - 0.5f) / 2.0f + 0.5f;
649			} else if (render_mode == ERenderMode::EncodingVis) {
650				rgb = warped_pos;
651			} else if (render_mode == ERenderMode::Depth) {
652				float d = is_360 ? distance(pos, origin) : dot(cam_fwd, pos - origin);
653				rgb = vec3(d * depth_scale);
654			} else if (render_mode == ERenderMode::AO) {
655				rgb = vec3(alpha);
656			}
657	
658			if (show_accel >= 0) {
659				uint32_t mip = max((uint32_t)show_accel, mip_from_pos(pos));
660				uint32_t res = NERF_GRIDSIZE() >> mip;
661				int ix = pos.x * res;
662				int iy = pos.y * res;
663				int iz = pos.z * res;
664				default_rng_t rng(ix + iy * 232323 + iz * 727272);
665				rgb.x = 1.f - mip * (1.f / (NERF_CASCADES() - 1));
666				rgb.y = rng.next_float();
667				rgb.z = rng.next_float();
668			}
669	
