671			if (weight > payload.max_weight) {
672				payload.max_weight = weight;
673				local_depth = is_360 ? distance(pos, camera_matrix[3]) : dot(cam_fwd, pos - camera_matrix[3]);
674			}
675	
676			if (local_rgba.a > (1.0f - min_transmittance)) {
677				local_rgba /= local_rgba.a;
678				break;
679			}
