100	inline NGP_HOST_DEVICE LossAndGradient huber_loss(const vec3& target, const vec3& prediction, float alpha = 1) {
101		vec3 difference = prediction - target;
102		vec3 abs_diff = abs(difference);
103		vec3 square = 0.5f/alpha * difference * difference;
104		return {
105			{
106				abs_diff.x > alpha ? (abs_diff.x - 0.5f * alpha) : square.x,
107				abs_diff.y > alpha ? (abs_diff.y - 0.5f * alpha) : square.y,
108				abs_diff.z > alpha ? (abs_diff.z - 0.5f * alpha) : square.z,
109			},
110			{
111				abs_diff.x > alpha ? (difference.x > 0 ? 1.0f : -1.0f) : (difference.x / alpha),
112				abs_diff.y > alpha ? (difference.y > 0 ? 1.0f : -1.0f) : (difference.y / alpha),
113				abs_diff.z > alpha ? (difference.z > 0 ? 1.0f : -1.0f) : (difference.z / alpha),
114			},
115		};
116	}
